// C solution using GNU MP (gmp) for big integers
// Compile with: gcc -std=cgnu11 -lgmp -O2 solution.c -o solution
#include <stdio.h>
#include <gmp.h>

void sum_powers(int K, long long N, mpz_t result) {
    // Use formulas for K = 1..4
    mpz_t tmp; mpz_init(tmp);
    if (K == 1) {
        // N(N+1)/2
        mpz_set_ui(result, N);
        mpz_mul_ui(result, result, N + 1);
        mpz_fdiv_q_ui(result, result, 2);
    } else if (K == 2) {
        // N(N+1)(2N+1)/6
        mpz_set_ui(result, N);
        mpz_mul_ui(result, result, N + 1);
        mpz_mul_ui(result, result, 2 * N + 1);
        mpz_fdiv_q_ui(result, result, 6);
    } else if (K == 3) {
        // (N(N+1)/2)^2
        mpz_set_ui(result, N);
        mpz_mul_ui(result, result, N + 1);
        mpz_fdiv_q_ui(result, result, 2);
        mpz_mul(result, result, result);
    } else { // K == 4
        // N(N+1)(2N+1)(3N^2+3N-1)/30
        mpz_set_ui(result, N);
        mpz_mul_ui(result, result, N + 1);
        mpz_mul_ui(result, result, 2 * N + 1);
        // compute 3N^2+3N-1
        mpz_set_ui(tmp, N);
        mpz_mul(tmp, tmp, tmp); // N^2
        mpz_mul_ui(tmp, tmp, 3); // 3N^2
        mpz_add_ui(tmp, tmp, 3 * N); // +3N
        mpz_sub_ui(tmp, tmp, 1); // -1
        mpz_mul(result, result, tmp);
        mpz_fdiv_q_ui(result, result, 30);
    }
    mpz_clear(tmp);
}

int main(){
    int K; if(scanf("%d", &K)!=1) return 0;
    int T; scanf("%d", &T);
    while(T--){
        long long N; scanf("%lld", &N);
        mpz_t total, half, curA, powi; 
        mpz_inits(total, half, curA, powi, NULL);
        sum_powers(K, N, total);
        mpz_fdiv_q_2exp(half, total, 1); // floor(total/2)
        mpz_set_ui(curA, 0);
        char *ans = (char*)malloc(N+1);
        ans[N] = '\0';
        for(long long i=N;i>=1;--i){
            // compute i^K
            mpz_set_ui(powi, i);
            for(int e=1;e<K;++e) mpz_mul_ui(powi, powi, i);
            mpz_t tmp; mpz_init(tmp);
            mpz_add(tmp, curA, powi);
            if(mpz_cmp(tmp, half) <= 0){
                ans[i-1] = '1';
                mpz_add(curA, curA, powi);
            } else {
                ans[i-1] = '0';
            }
            mpz_clear(tmp);
        }
        // diff = total - 2*curA
        mpz_mul_ui(powi, curA, 2);
        mpz_sub(powi, total, powi);
        gmp_printf("%Zd\n%s\n", powi, ans);
        free(ans);
        mpz_clears(total, half, curA, powi, NULL);
    }
    return 0;
}
